1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const COMPONENT_BLOCK_OF_3_PRICE = 60;
4	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	type Item = { type: string };
16	type QuoteStep = { type: "quote"; items: Item[] };
17	type Scenario = { steps: QuoteStep[] };
18	
19	function groupByType(items: Item[]): Map<string, Item[]> {
20	  const groups = new Map<string, Item[]>();
21	  for (const item of items) {
22	    const group = groups.get(item.type) ?? [];
23	    group.push(item);
24	    groups.set(item.type, group);
25	  }
26	  return groups;
27	}
28	
29	function calculateGroupPremium(type: string, group: Item[]): number {
30	  if (COMPONENT_TYPES.has(type) && group.length === 3) {
31	    return COMPONENT_BLOCK_OF_3_PRICE;
32	  }
33	  return group.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
34	}
35	
36	function calculateBasePremium(items: Item[]): number {
37	  return Array.from(groupByType(items)).reduce(
38	    (total, [type, group]) => total + calculateGroupPremium(type, group),
39	    0,
40	  );
41	}
42	
43	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
44	  const { steps } = scenario as Scenario;
45	  const items = steps[0].items;
46	  const basePremium = calculateBasePremium(items);
47	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
48	  const premium = basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
49	  return { results: [{ premium }] };
50	}
